Set-StrictMode -Version 2.0
function Invoke-GodModeNetworkDoctor { param([string]$Project='.') $r=Initialize-GodModeStructure $Project; $loop=$false; try{$l=[Net.Sockets.TcpListener]::new([Net.IPAddress]::Parse('127.0.0.1'),0);$l.Start();$l.Stop();$loop=$true}catch{}; $dns='not_probed'; try{$x=Resolve-DnsName registry.npmjs.org -QuickTimeout -ErrorAction Stop|select -First 1;if($x){$dns='ok'}}catch{$dns='failed'}; $h=@{schema_version=1;generated_at=Get-GodModeIso;host_powershell_localhost=$loop;codex_sandbox_localhost='unknown';host_dns=$dns;codex_sandbox_dns='unknown';npm_registry_reachability='not_probed_no_install';pip_index_reachability='not_probed';github_reachability='not_probed';proxy_environment=@{HTTP_PROXY=$env:HTTP_PROXY;HTTPS_PROXY=$env:HTTPS_PROXY;NO_PROXY=$env:NO_PROXY};network_access_allowed_for_commands='unknown';degraded_reasons=@();blockers=@()}; if(-not $loop){$h.blockers+='loopback_bind_failed'}; Write-GodModeJsonAtomic (Join-GodModePath $r 'state/network-health.json') $h|Out-Null; $h }
